import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.crustdata.com/general/introduction";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCof";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Crustdata API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:crustdata",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const crustdataFirewall = {",
    '  name: "crustdata",',
    '  description: "Crustdata",',
    "  placeholders: {",
    `    CRUSTDATA_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.crustdata.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CRUSTDATA_TOKEN }}",',
    '          "x-api-version": "2025-11-01",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Crustdata firewall config...");
  const ts = generateTypeScript();
  writeOutput("crustdata", ts, import.meta.dirname);
}
